+                        repeat = repeat * 10 + ch - '0';
+                        if (repeat > TerminalSixel.SIXEL__MAX_REPEAT) {
+                            Logger.logError(mClient, LOG_TAG, "The sixel repeat command Pn value " + repeat + " is greater than max repeat value " +
