From 253eee9ba5412e60911dd1c04697f9fdf7be86a6 Mon Sep 17 00:00:00 2001
From: agnostic-apollo <agnosticapollo@gmail.com>
Date: Tue, 14 Apr 2026 16:05:44 +0500
Subject: [PATCH 10/11] Changed: Increase OCS 52 buffer limit to `100KB` for
 text to set to clipboard

---
 .../main/java/com/termux/terminal/TerminalEmulator.java   | 8 ++++++++
 1 file changed, 8 insertions(+)

diff --git a/terminal-emulator/src/main/java/com/termux/terminal/TerminalEmulator.java b/terminal-emulator/src/main/java/com/termux/terminal/TerminalEmulator.java
index aada13b78f..5c6dcdec7b 100644
--- a/termux-app/terminal-emulator/src/main/java/com/termux/terminal/TerminalEmulator.java
+++ b/termux-app/terminal-emulator/src/main/java/com/termux/terminal/TerminalEmulator.java
@@ -2694,6 +2694,14 @@ void setOscTypeVariables() {
             Integer terminalControlArgsCapacity = null;
             Integer terminalControlArgsMaxLength = null;
             switch (mOscType) {
+                case 52:
+                    // Android has a `~100KB` limit for sharing/sending `UTF-16` encoded `String`
+                    // with binder tranasactions, including clipboard, otherwise can result in a
+                    // `TransactionTooLargeException`.
+                    // - https://www.reddit.com/r/tasker/comments/prro8t/autoshare_crashed_when_i_pasted_the_file_path/
+                    terminalControlArgsMaxLength = (100 * 1024)  +
+                        /* `52;Pc;` */ 10;
+                    break;
                 case 1337: // iTerm image command sends the base64 encoded image, do not run complex logic for each byte.
                     mIsFastPathOsc = true;
                     mIgnoreCrLfForOsc = true;

